/*
ULHostInstanceSet - 轻量应用云主机详情
*/
type ULHostInstanceSet struct {

	// 【数组】镜像包含的应用列表。
	Apps []string

	// 是否自动续费。枚举值：Yes/No
	AutoRenew string

	// CPU核数。
	CPU int

	// 计费模式。枚举值：Month/Year
	ChargeType string

	// 创建时间。Unix时间戳
	CreateTime int

	// 磁盘信息
	DiskSet []ULHostDiskSet

	// 流量包详情信息
	EIPExclusiveUTPInfo ExclusiveUTPInfo

	// 过期时间。Unix时间戳
	ExpireTime int

	// IP信息
	IPSet []UHostIPSet

	// 镜像Id。
	ImageId string

	// 镜像名称。
	ImageName string

	// 是否过期。枚举值：Yes/No
	IsExpire string

	// 内存。单位：MB
	Memory int

	// 实例名称。默认套餐Id
	Name string

	// 备注。
	Remark string

	// 实例状态。枚举值：\\ >初始化: Initializing; \\ >启动中: Starting; \\> 运行中: Running; \\> 关机中: Stopping; \\ >关机: Stopped \\ >安装失败: Install Fail; \\ >重启中: Rebooting; \\ > 未知(空字符串，获取状态超时或出错)：""
	State string

	// 业务组。
	Tag string

	// 实例Id。
	ULHostId string

	// 可用区。
	Zone string
}

